VALUES
  ('immigration-1aab856d-moex-00180', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '送達文書是海峽兩岸司法互助的重點措施之一，試問依據法務部所訂之《海峽兩岸送達文書作業 要點》，下列敘述何者正確？', '["文書係指與民事或刑事訴訟程序有關而非作為證據之文書", "送達文書的「大陸地區主管機關」係指海峽兩岸關係協會", "法務部為辦理兩岸司法文書送達事務，應逕以法務部名義執行", "法務部為辦理兩岸司法文書送達事務，得移請大陸委員會逕以法務部協議聯絡人名義執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00181', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據《內政部移民署組織法》規定，內政部移民署於入出國（境）安全與移民資料之蒐集及事證 之調查若有涉及國家安全情報事項者，應受下列何者之指導、協調及支援？', '["國防部軍事情報局", "法務部調查局", "國家安全局", "國家安全會議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00182', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據《人口販運被害人及疑似人口販運被害人安置服務管理規則》，有關人口販運被害人的保護 規定，下列敘述何者正確？', '["被害人若為臺灣地區無戶籍國民，由直轄市、縣（市）主管機關負責安置", "被害人若為大陸地區人民、香港或澳門居民，由大陸委員會負責安置", "被害人若為無國籍人民，由僑務委員會負責安置", "被害人若為持有工作簽證之外國人，由勞動部負責安置"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00183', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '依據《內政部移民署處務規程》規定，掌理入出國（境）證照之查驗、鑑識及許可者為下列何者？', '["國境事務大隊", "移民資訊組", "國際及執法事務組", "入出國事務組"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00184', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '引渡是屬於傳統國際司法互助的措施之一，試問依據我國現行法令規定，有關我國引渡制度之敘 述，下列何者正確？', '["執行引渡之法律依據為《國際刑事司法互助法》", "引渡之請求，應循外交途徑向我國管轄法院為之", "請求引渡之犯罪，業經我國法院不起訴或正在審理中，應拒絕引渡", "非經我國政府同意，不得追訴或處罰引渡請求書所載以外之犯罪，此為雙罰性原則之具體規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00185', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '我國籍的漁船停泊於基隆港之際，船上印尼籍的漁工甲與我國籍的漁工乙發生爭執，甲因而持利 刃將乙刺死於漁船上。關於甲之殺人行為得否適用我國刑法處罰，下列敘述何者正確？', '["屬於發生於我國領域內之犯罪行為，因符合刑法第3條前段規定，得適用我國刑法處罰", "屬於發生於我國國籍船艦內之犯罪行為，因符合刑法第3條後段規定，得適用我國刑法處罰", "屬於外國人對我國人民之犯罪行為，因符合刑法第8條之規定，得適用我國刑法處罰", "甲之行為不在我國刑法之適用效力範圍內，不適用我國刑法處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00186', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於刑法上「正當防衛」此一阻卻違法事由之敘述，下列何者錯誤？', '["對於未來可能發生或過去已經發生之侵害，不得主張正當防衛", "行為人除得防衛自己之權利外，亦得防衛第三人之權利", "防衛行為若波及攻擊者以外之第三人，對受到侵害之第三人亦得主張正當防衛", "如防衛行為逾越必要性時，雖不得阻卻違法，但得減輕或免除刑罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00187', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲欲殺害乙，於發現乙的行蹤後，遂持利刃朝其連刺數刀，但隨後發現所殺者其實為丙。甲認為 不該牽連無辜的丙，遂呼叫救護車將丙送醫救治，惟丙經搶救仍不幸身亡。對於甲應負之刑事責 任，下列敘述何者正確？', '["甲成立殺人未遂罪及過失致死罪，依想像競合犯論處", "甲成立殺人既遂罪", "甲成立殺人未遂罪，但得依中止未遂規定減輕或免除刑罰", "甲成立殺人既遂罪，但得依準中止未遂規定減輕或免除刑罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00188', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '公務員甲利用職務上之機會向廠商索取賄款，但甲擔心自己親自收取賄款有遭到廉政單位發覺之 可能，遂與其妻乙商量，由乙前往廠商處收取賄款以掩人耳目。關於甲、乙二人之刑事責任，下 列敘述何者正確？', '["甲成立「公務員收受賄賂罪」之正犯，乙不成立犯罪", "甲成立「公務員收受賄賂罪」之正犯，乙成立「公務員收受賄賂罪」之幫助犯", "甲成立「公務員收受賄賂罪」之間接正犯，乙不成立犯罪", "甲、乙成立「公務員收受賄賂罪」之共同正犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00189', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲因交通違規遭到警員乙開單裁罰而甚為不滿，數日後，甲在餐廳用餐時，恰巧遇到下班後也前 來用餐的乙，甲遂在餐廳對乙怒罵：「你這個穿著制服的流氓，我一下就認出是你了！」對此， 甲之行為應成立何罪？', '["成立刑法第140條之「侮辱公務員罪」", "成立刑法第135條第1項「妨害公務罪」", "成立刑法第309條第1項之「公然侮辱罪」", "成立刑法第310條第1項之「誹謗罪」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
